local class = require "class"
local define = require "define"
local script_base = require "script_base"
local event_shimen_shop = class("event_shimen_shop", script_base)event_shimen_shop.script_id = 229012function event_shimen_shop:OnDefaultEvent(selfId,targetId)local NumText = indexif (NumText == 1) thenself:BeginEvent(self.script_id)self:AddNumText("2섬토렘",7,3)self:AddNumText("3섬토렘",7,4)self:AddNumText("4섬토렘",7,5)self:AddNumText("5섬토렘",7,6)self:AddNumText("6섬토렘",7,7)self:AddNumText("7섬토렘",7,8)self:EndEvent()self:DispatchEventList(selfId,targetId)elseif (NumText == 2) thenself:BeginEvent(self.script_id)self:AddNumText("2섬토렘",7,3)self:AddNumText("3섬토렘",7,4)self:AddNumText("4섬토렘",7,5)self:AddNumText("5섬토렘",7,6)self:AddNumText("6섬토렘",7,7)self:AddNumText("7섬토렘",7,8)self:AddNumText("8섬토렘",7,9)self:AddNumText("9섬토렘",7,10)self:AddNumText("10섬토렘",7,11)self:EndEvent()self:DispatchEventList(selfId,targetId)elseif (NumText >= 3 and NumText <= 11) thenself:OpenShopNumText(selfId,targetId,NumText)endendfunction event_shimen_shop:OnEnumerate(caller,selfId,targetId,arg,index)local lev = self:GetLevel(selfId)if (lev >= 40 and lev < 70) thenself:AddNumText("뭔찜토렘",7,1)elseif (lev >= 70) thenself:AddNumText("뭔찜토렘",7,2)endendfunction event_shimen_shop:OpenShopNumText(selfId,targetId,shopNumText)if (shopNumText == 3) thenself:DispatchShopItem(selfId,targetId,169)elseif (shopNumText == 4) thenself:DispatchShopItem(selfId,targetId,170)elseif (shopNumText == 5) thenself:DispatchShopItem(selfId,targetId,171)elseif (shopNumText == 6) thenself:DispatchShopItem(selfId,targetId,172)elseif (shopNumText == 7) thenself:DispatchShopItem(selfId,targetId,173)elseif (shopNumText == 8) thenself:DispatchShopItem(selfId,targetId,174)elseif (shopNumText == 9) thenself:DispatchShopItem(selfId,targetId,175)elseif (shopNumText == 10) thenself:DispatchShopItem(selfId,targetId,176)elseif (shopNumText == 11) thenself:DispatchShopItem(selfId,targetId,177)endendreturn event_shimen_shop